class Solution {
    public int minSwaps(int[] nums) {
        int n = nums.length;
        int ones = 0;
        for (int num : nums) {
            ones += num;
        }
        int left = 0, right = 0, minSwaps = n;
        for (int i = 0; i < n; i++) {
            right += nums[i];
            left += nums[(i + ones) % n];
            minSwaps = Math.min(minSwaps, Math.min(left, right) + (n - ones));
        }
        return minSwaps - ones;
    }
}
